                    <div style={{ display: "flex", justifyContent: "space-between", gap: "8px", alignItems: "center" }}>
                      <div>
                        <strong style={{ color: "var(--population-primary)", fontSize: "15px" }}>خصائص الخطوة</strong>
                        <p style={{ margin: "4px 0 0", color: "var(--population-muted)", fontSize: "12px" }}>
                          اربط الحقول أو غيّر موضع الخطوة من هنا.
                        </p>
                      </div>
                      <label style={{ display: "flex", alignItems: "center", gap: "6px", fontSize: "12px", color: "var(--population-muted)" }}>
                        <input
                          type="checkbox"
                          checked={selectedWorkflowStep.isEnabled}
                          onChange={(event) => handleWorkflowStepChange(selectedWorkflowStep.stepId, { isEnabled: event.target.checked })}
                        />
                        مفعل
                      </label>
                    </div>

                    <label className="save-disk-label">
                      اسم الخطوة
                      <input
                        type="text"
                        className="save-disk-input"
                        value={selectedWorkflowStep.titleAr}
                        onChange={(event) => handleWorkflowStepChange(selectedWorkflowStep.stepId, { titleAr: event.target.value })}
                      />
                    </label>

                    <label className="save-disk-label">
                      نوع الخطوة
                      <select
                        className="save-disk-input"
                        value={selectedWorkflowStep.kind}
                        onChange={(event) => handleWorkflowStepChange(selectedWorkflowStep.stepId, { kind: event.target.value as ProcessingStepKind })}
                      >
                        {(Object.keys(stepKindLabels) as ProcessingStepKind[]).map((kind) => (
                          <option key={kind} value={kind}>{stepKindLabels[kind]}</option>
                        ))}
                      </select>
                    </label>

                    <label className="save-disk-label">
                      وصف الخطوة
                      <textarea
                        className="save-disk-input"
                        rows={3}
                        value={selectedWorkflowStep.descriptionAr}
                        onChange={(event) => handleWorkflowStepChange(selectedWorkflowStep.stepId, { descriptionAr: event.target.value })}
                        style={{ resize: "vertical", minHeight: "72px" }}
                      />
                    </label>

                    <div style={{ border: "1px solid #e2e8f0", borderRadius: "10px", padding: "10px", background: "#f8fafc" }}>
                      <strong style={{ display: "block", marginBottom: "8px", color: "#334155", fontSize: "13px" }}>ربط أو إرفاق الحقول</strong>
                      <label className="save-disk-label" style={{ marginBottom: "8px" }}>
                        الحقل المصدر
                        <select
                          className="save-disk-input"
                          value={selectedWorkflowStep.sourceField ?? ""}
                          onChange={(event) => handleWorkflowStepChange(selectedWorkflowStep.stepId, { sourceField: event.target.value || undefined })}
                        >
                          <option value="">بدون</option>
                          {fieldOptions.map((field) => (
                            <option key={field.key} value={field.key}>{field.label} ({field.key})</option>
                          ))}
                        </select>
                      </label>
                      <label className="save-disk-label">
                        الحقل الهدف
                        <select
                          className="save-disk-input"
                          value={selectedWorkflowStep.targetField ?? ""}
                          onChange={(event) => handleWorkflowStepChange(selectedWorkflowStep.stepId, { targetField: event.target.value || undefined })}
                        >
                          <option value="">بدون</option>
                          {fieldOptions.map((field) => (
                            <option key={field.key} value={field.key}>{field.label} ({field.key})</option>
                          ))}
                        </select>
                      </label>
                    </div>

                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "8px" }}>
                      <button
                        type="button"
                        className="secondary-action"
                        onClick={() => handleMoveWorkflowStep(selectedWorkflowStep.stepId, "up")}
                        disabled={workflowSteps[0]?.stepId === selectedWorkflowStep.stepId}
                      >
                        تحريك لأعلى
                      </button>
                      <button
                        type="button"
                        className="secondary-action"
                        onClick={() => handleMoveWorkflowStep(selectedWorkflowStep.stepId, "down")}
                        disabled={workflowSteps[workflowSteps.length - 1]?.stepId === selectedWorkflowStep.stepId}
                      >
                        تحريك لأسفل
                      </button>
                    </div>

                    <button
                      type="button"
                      className="secondary-action"
                      onClick={() => handleInsertWorkflowStepAfter(selectedWorkflowStep.stepId)}
                    >
                      إرفاق خطوة بعد هذه الخطوة
                    </button>

                    {selectedWorkflowStep.kind === "custom" && (
                      <button
                        type="button"
                        onClick={() => handleRemoveWorkflowStep(selectedWorkflowStep.stepId)}
                        style={{ border: "none", borderRadius: "8px", background: "#fee2e2", color: "#b91c1c", padding: "9px 12px", cursor: "pointer", fontWeight: 800 }}
                      >
                        حذف الخطوة المخصصة
                      </button>
                    )}
                  </div>
                ) : (
                  <p style={{ color: "var(--population-muted)", margin: 0 }}>اختر خطوة من الخريطة لتعديلها.</p>
                )}
              </aside>
            </div>
          )}

          {activeTab === "stages" && (
            <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
              <p style={{ fontSize: "13px", color: "var(--population-muted)" }}>
                حدد الكلمات أو القيم التي تعني كل مستوى. سيتم استخدام هذه القائمة في العرض، التصفية، المؤشرات، سحب العينة، والتوزيع. افصل بين القيم بفواصل.
              </p>

              {(Object.keys(stageLabels) as StageKey[]).map((stageKey) => (
                <label key={stageKey} className="save-disk-label">
                  {stageLabels[stageKey]}
                  <input
                    type="text"
                    className="save-disk-input"
                    value={(stageMappings[stageKey] || []).join(", ")}
                    onChange={(e) => handleStageMappingChange(stageKey, e.target.value)}
                  />
                </label>
              ))}

              <button
                type="button"
                className="secondary-action"
                style={{ alignSelf: "flex-start" }}
                onClick={handleResetStageMappings}
              >
                استعادة القائمة الافتراضية
              </button>
            </div>
          )}

          {activeTab === "sheets" && (
            <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
              <p style={{ fontSize: "13px", color: "var(--population-muted)" }}>
                قم بتكوين الكلمات المفتاحية لمطابقة أسماء أوراق العمل (Sheets) في الملفات المرفوعة.
              </p>

              <label className="save-disk-label">
                أنماط أسماء أوراق المخاطر (Risk Sheet Patterns)
                <input
                  type="text"
                  className="save-disk-input"
                  value={template.sheetPatterns.risk.join(", ")}
                  onChange={(e) => handleSheetPatternChange("risk", e.target.value)}
                />
              </label>

              <label className="save-disk-label">
                أنماط أسماء أوراق ذكاء الأعمال (BI Sheet Patterns)
                <input
                  type="text"
                  className="save-disk-input"
                  value={template.sheetPatterns.bi.join(", ")}
                  onChange={(e) => handleSheetPatternChange("bi", e.target.value)}
                />
              </label>
            </div>
          )}

          {activeTab === "exports" && (
            <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
              <p style={{ fontSize: "13px", color: "var(--population-muted)" }}>
                تحكم في تفعيل أو تعطيل، ترتيب، وتغيير عناوين الأعمدة المخرجة عند تصدير العينات لملفات Excel.
              </p>

              <div className="report-sheet-table" role="table">
                <div className="report-sheet-header" role="row" style={{ gridTemplateColumns: "auto 2fr 2fr 1fr" }}>
                  <span>الترتيب</span>
                  <span>اسم الحقل</span>
                  <span>عنوان التصدير</span>
                  <span>مفعل</span>
                </div>

                {[...(config.exportTemplates[0]?.columns || [])]
                  .sort((a: any, b: any) => a.order - b.order)
                  .map((col: any, idx: number, arr: any[]) => (
                    <div key={col.fieldKey} className="report-sheet-row" role="row" style={{ gridTemplateColumns: "auto 2fr 2fr 1fr", alignItems: "center" }}>
                      <span style={{ display: "flex", flexDirection: "column", gap: "2px", alignItems: "center" }}>
                        <button
                          type="button"
                          disabled={idx === 0}
                          onClick={() => handleMoveColumn(col.fieldKey, "up")}
                          style={{
                            width: "26px", height: "22px", border: "1px solid var(--population-border)",
                            borderRadius: "4px", background: idx === 0 ? "#f8fafc" : "#fff",
                            cursor: idx === 0 ? "default" : "pointer", fontSize: "11px",
                            color: idx === 0 ? "#ccc" : "var(--population-primary)", lineHeight: 1
                          }}
                          title="تحريك لأعلى"
                        >▲</button>
                        <button
                          type="button"
                          disabled={idx === arr.length - 1}
                          onClick={() => handleMoveColumn(col.fieldKey, "down")}
                          style={{
                            width: "26px", height: "22px", border: "1px solid var(--population-border)",
                            borderRadius: "4px", background: idx === arr.length - 1 ? "#f8fafc" : "#fff",
                            cursor: idx === arr.length - 1 ? "default" : "pointer", fontSize: "11px",
                            color: idx === arr.length - 1 ? "#ccc" : "var(--population-primary)", lineHeight: 1
                          }}
                          title="تحريك لأسفل"
                        >▼</button>
                      </span>

                      <span style={{ fontSize: "12px", color: "var(--population-muted)", fontFamily: "monospace" }}>
                        {col.fieldKey}
                      </span>

                      <span>
                        <input
                          type="text"
                          className="save-disk-input"
                          style={{ padding: "4px", margin: 0 }}
                          value={col.exportHeader}
                          onChange={(e) => handleExportColumnChange(col.fieldKey, "exportHeader", e.target.value)}
                        />
                      </span>

                      <span style={{ textAlign: "center" }}>
                        <input
                          type="checkbox"
                          checked={col.isEnabled}
                          onChange={(e) => handleExportColumnChange(col.fieldKey, "isEnabled", e.target.checked)}
                        />
                      </span>
                    </div>
                  ))}
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{ padding: "16px 20px", borderTop: "1px solid var(--population-border)", display: "flex", justifyContent: "flex-end" }}>
          <button type="button" className="primary-action" onClick={onClose}>
            حفظ وإغلاق
          </button>
        </div>
      </div>
    </div>
  );
}

import { getManagedLoginUsers } from "../../../../../auth/userManagement";
import type { SampleMasterData } from "../../../../../data/sampling/sampleTypes";
import type { DistributionCurrentData } from "../../../../../data/distribution/distributionTypes";
import type { PopulationConfig, EmployeeStageAllocation } from "../../../../../data/population/populationConfig";
import SummaryCard from "./SummaryCard";
import DistributionRow from "./DistributionRow";
import { useState, useMemo } from "react";
import { getStageKey, formatNumber } from "./helpers";
import { calculateBulkAssignment } from "../../../../../data/distribution/bulkAssignment";

type SaveMessage = { type: "ok" | "error"; text: string } | null;

type PhaseFourDistributionProps = {
  sampleDrawResult: SampleMasterData | null;
  distributionCurrent: DistributionCurrentData | null;
  distributionMessage: SaveMessage;
  isDistributing: boolean;
  config: PopulationConfig;
  operatorUsername: string;
  saveMonth: number;
  saveYear: number;
  onConfigChange: (config: PopulationConfig) => void;
  onAssign: (xrayImageId: string, assignedTo: string) => Promise<void>;
  onReassign: (xrayImageId: string, reassignedTo: string) => Promise<void>;
  onMarkComplete: (xrayImageId: string) => Promise<void>;
  onRequestReplacement: (xrayImageId: string) => Promise<void>;
  onApplyBulkAssignment: (events: any[]) => Promise<void>;
};

const STAGE_LABELS: Record<string, string> = {
  first:  "المستوى الأول",
  second: "المستوى الثاني",
  third:  "المستوى الثالث",
  fourth: "المستوى الرابع"
};

export default function PhaseFourDistribution({
  sampleDrawResult,
  distributionCurrent,
  distributionMessage,
  isDistributing,
  config,
  operatorUsername,
  saveMonth,
  saveYear,
  onConfigChange,
  onAssign,
  onReassign,
  onMarkComplete,
  onRequestReplacement,
  onApplyBulkAssignment
}: PhaseFourDistributionProps) {
  const [activeTab, setActiveTab] = useState<"bulk" | "manual">("bulk");
  const [selectedStageTab, setSelectedStageTab] = useState<"first" | "second" | "third" | "fourth">("first");
  const [bulkError, setBulkError] = useState("");

  const employees = useMemo(
    () =>
      getManagedLoginUsers()
        .filter((u: any) => u.isActive)
        .map((u: any) => ({
          username: u.username,
          displayName: u.displayName,
          hasCertScanLicense: u.hasCertScanLicense
        })),
    []
  );

  const sampleRows = sampleDrawResult?.rows || [];

  const stageSampleCounts = useMemo(
    () => ({
      first:  sampleRows.filter((r) => getStageKey(r.stage, config.stageMappings) === "first"),
      second: sampleRows.filter((r) => getStageKey(r.stage, config.stageMappings) === "second"),
      third:  sampleRows.filter((r) => getStageKey(r.stage, config.stageMappings) === "third"),
      fourth: sampleRows.filter((r) => getStageKey(r.stage, config.stageMappings) === "fourth")
    }),
    [sampleRows, config.stageMappings]
  );

  const activeAllocations = useMemo(() => {
    const list: EmployeeStageAllocation[] = [];
    const stageKeys = ["first", "second", "third", "fourth"] as const;
    for (const sKey of stageKeys) {
      for (const emp of employees) {
        const existing = config.employeeAllocations.find(
          (a) => a.username === emp.username && a.stageKey === sKey
        );
        list.push({
          username: emp.username,
          stageKey: sKey,
          method: existing?.method || "percentage",
          value: existing?.value !== undefined ? existing.value : 0,
          isActive: existing?.isActive || false,
          maxWorkload: existing?.maxWorkload
        });
      }
    }
    return list;
  }, [config.employeeAllocations, employees]);

  const handleAllocationChange = (
    username: string,
    stageKey: "first" | "second" | "third" | "fourth",
    field: keyof EmployeeStageAllocation,
    val: any
  ) => {
    const updated = activeAllocations.map((alloc) =>
      alloc.username === username && alloc.stageKey === stageKey
        ? { ...alloc, [field]: val }
        : alloc
    );
    onConfigChange({ ...config, employeeAllocations: updated });
  };

  const previewData = useMemo(() => {
    if (!sampleDrawResult) return null;
    const { events, errors } = calculateBulkAssignment({
      rows: sampleRows,
      allocations: activeAllocations,
      employees: getManagedLoginUsers(),
      operatorUsername,
      stageMappings: config.stageMappings,
      month: saveMonth,
      year: saveYear,
    });

    const summaryMap: Record<string, { cert: number; normal: number; total: number }> = {};
    for (const emp of employees) {
      summaryMap[emp.username] = { cert: 0, normal: 0, total: 0 };
    }

    for (const evt of events) {
      const row = sampleRows.find((r) => r.xrayImageId === evt.xrayImageId);
      const data = summaryMap[evt.assignedTo];
      if (data && row) {
        data.total += 1;
        if (row.certScanStatus === "Certscan") data.cert += 1;
        else data.normal += 1;
      }
    }

    return { summaryMap, errors };
  }, [sampleDrawResult, sampleRows, activeAllocations, employees, operatorUsername, config.stageMappings]);

  if (!sampleDrawResult) {
    return (
      <section className="placeholder-phase">
        <h2>توزيع العينة</h2>
        <p>يجب إتمام سحب العينة في المرحلة السابقة أولاً.</p>
      </section>
    );
  }

  const entryMap = new Map(
    (distributionCurrent?.entries ?? []).map((e: any) => [e.xrayImageId, e])
  );

  const handleRunBulkAssignment = async () => {
    setBulkError("");
    const { events, errors } = calculateBulkAssignment({
      rows: sampleRows,
      allocations: activeAllocations,
      employees: getManagedLoginUsers(),
      operatorUsername,
      stageMappings: config.stageMappings,
      month: saveMonth,
      year: saveYear,
    });

    if (errors.length > 0) {
      setBulkError(`تحذير: ${errors.join(" | ")} — الصفوف المتأثرة ستبقى غير معينة ويمكن تعيينها يدوياً.`);
    }

    await onApplyBulkAssignment(events);
  };

  return (
    <section className="distribution-phase" aria-label="توزيع العينة">
      <div className="phase-panel-header compact">
        <div>
          <h2>المرحلة 4: توزيع العينة</h2>
          <p>
            توزيع العينة الكلية على الموظفين الفعالين. يدعم التوزيع الجماعي
            الذكي حسب كوتا كل مستوى والتوزيع اليدوي لكل صف.
          </p>
        </div>
      </div>

      {/* Summary Cards */}
      {distributionCurrent && (
        <div className="processing-summary-grid">
          <SummaryCard label="إجمالي المعينة" value={distributionCurrent.totalAssigned} />
          <SummaryCard label="قيد الانتظار"   value={distributionCurrent.totalPending} />
          <SummaryCard label="مكتملة"          value={distributionCurrent.totalCompleted} />
          <SummaryCard label="مستبدلة"         value={distributionCurrent.totalReplaced} />
        </div>
      )}

      {distributionMessage && (
        <div
          className={distributionMessage.type === "ok" ? "msg-success" : "msg-error"}
          role="status"
        >
          {distributionMessage.text}
        </div>
      )}

      {/* Tab bar */}
      <div className="dist-tab-bar" role="tablist">
        <button
          role="tab"
          type="button"
          className={`dist-tab-btn${activeTab === "bulk" ? " active" : ""}`}
          aria-selected={activeTab === "bulk"}
          onClick={() => setActiveTab("bulk")}
        >
          ⚙️ التوزيع الجماعي الذكي
        </button>
        <button
          role="tab"
          type="button"
          className={`dist-tab-btn${activeTab === "manual" ? " active" : ""}`}
          aria-selected={activeTab === "manual"}
          onClick={() => setActiveTab("manual")}
        >
          📝 المراجعة اليدوية
        </button>
      </div>

      {activeTab === "bulk" ? (
        <div className="distribution-phase">
          {/* Stage selector */}
          <div className="dist-stage-bar" role="tablist" aria-label="اختيار المستوى">
            {(["first", "second", "third", "fourth"] as const).map((sk) => (
              <button
                key={sk}
                role="tab"
                type="button"
                className={`dist-stage-btn${selectedStageTab === sk ? " active" : ""}`}
                aria-selected={selectedStageTab === sk}
                onClick={() => setSelectedStageTab(sk)}
              >
                {STAGE_LABELS[sk]} ({formatNumber(stageSampleCounts[sk].length)})
              </button>
            ))}
          </div>

          {/* Allocation config */}
          <div className="dist-config-card">
            <h3>إعدادات توزيع موظفي {STAGE_LABELS[selectedStageTab]}</h3>
            <div className="dist-alloc-table report-sheet-table" role="table">
              <div className="dist-alloc-header" role="row">
                <span>الموظف</span>
                <span>تفعيل بالمستوى</span>
                <span>طريقة التوزيع</span>
                <span>الحصة / النسبة</span>
                <span>ترخيص CertScan</span>
              </div>

              {employees.map((emp) => {
                const alloc = activeAllocations.find(
                  (a) => a.username === emp.username && a.stageKey === selectedStageTab
                )!;
                return (
                  <div key={emp.username} className="dist-alloc-row" role="row">
                    <span>
                      {emp.displayName}{" "}
                      <code style={{ fontSize: "11px", color: "var(--p-muted)" }}>
                        ({emp.username})
                      </code>
                    </span>

                    <span>
                      <input
                        type="checkbox"
                        checked={alloc.isActive}
                        onChange={(e) =>
                          handleAllocationChange(emp.username, selectedStageTab, "isActive", e.target.checked)
                        }
                      />
                    </span>

                    <span>
                      <select
                        className="save-disk-input"
                        disabled={!alloc.isActive}
                        value={alloc.method}
                        onChange={(e) =>
                          handleAllocationChange(emp.username, selectedStageTab, "method", e.target.value)
                        }
                      >
                        <option value="percentage">نسبة مئوية (%)</option>
                        <option value="exact">عدد محدد</option>
                      </select>
                    </span>

                    <span>
                      <input
                        type="number"
                        className="save-disk-input"
                        disabled={!alloc.isActive}
                        min={0}
                        value={alloc.value}
                        onChange={(e) =>
                          handleAllocationChange(
                            emp.username,
                            selectedStageTab,
                            "value",
                            parseInt(e.target.value, 10) || 0
                          )
                        }
                      />
                    </span>

                    <span>
                      {emp.hasCertScanLicense ? (
                        <span className="report-status ok">✅ مرخص</span>
                      ) : (
                        <span className="report-status muted">❌ غير مرخص</span>
                      )}
                    </span>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Preview */}
          {previewData && (
            <div className="dist-preview-card">
              <h3>معاينة حصص الموظفين الناتجة (الحجم الكلي)</h3>
              <div className="dist-alloc-table report-sheet-table" role="table">
                <div className="dist-preview-header" role="row">
                  <span>الموظف</span>
                  <span>عادية</span>
                  <span>CertScan</span>
                  <span>المجموع المتوقع</span>
                </div>

                {employees.map((emp) => {
                  const counts = previewData.summaryMap[emp.username] || { cert: 0, normal: 0, total: 0 };
                  return (
                    <div key={emp.username} className="dist-preview-row" role="row">
                      <span>{emp.displayName}</span>
                      <span>{counts.normal}</span>
                      <span>{counts.cert}</span>
                      <strong>{counts.total}</strong>
                    </div>
                  );
                })}
              </div>

              {previewData.errors.length > 0 && (
                <div className="dist-err-block" role="alert">
                  ⚠️ {previewData.errors.join(" | ")}
                </div>
              )}
            </div>
          )}

          {bulkError && (
            <div className="msg-error" role="alert">
              {bulkError}
            </div>
          )}

          <div className="dist-footer-row">
            <button
              type="button"
              className="primary-action"
              onClick={handleRunBulkAssignment}
              disabled={isDistributing}
            >
              {isDistributing ? "جاري توزيع وحفظ التعيينات..." : "تطبيق وحفظ التوزيع التلقائي"}
            </button>
          </div>
        </div>
      ) : (
        <div className="distribution-table-wrapper">
          <div className="distribution-table" role="table">
            <div className="distribution-header" role="row">
              <span>معرف الأشعة</span>
              <span>المنفذ</span>
              <span>CertScan</span>
              <span>الحالة</span>
              <span>خبير جودة الأشعة</span>
              <span>الإجراء</span>
            </div>

            {sampleDrawResult.rows.map((row: any) => {
              const entry = entryMap.get(row.xrayImageId);
              return (
                <DistributionRow
                  key={row.xrayImageId}
                  row={row}
                  entry={entry ?? null}
                  employees={employees}
                  isDisabled={isDistributing}
                  onAssign={onAssign}
                  onReassign={onReassign}
                  onMarkComplete={onMarkComplete}
                  onRequestReplacement={onRequestReplacement}
                />
              );
            })}
          </div>
        </div>
      )}
    </section>
  );
}

